const QUERIES = ['auto repair shop', 'mechanic shop', 'auto service center'];
const CITIES_PER_BATCH = 10;

// Check if triggered by webhook with specific regions
const webhookData = $input.first().json;
const isWebhook = !!(webhookData.body && webhookData.body.regions);
const requestedRegions = isWebhook ? (webhookData.body.regions || []).map(r => r.toLowerCase()) : [];
const requestedQueries = isWebhook && webhookData.body.queries ? webhookData.body.queries : QUERIES;

// Get scrape progress from static data (tracks which city+query combos are done)
const staticData = $getWorkflowStaticData('global');
if (!staticData.scrapedCities) {
  staticData.scrapedCities = {}; // key: "city_state_query" => timestamp
}
if (!staticData.batchIndex) {
  staticData.batchIndex = 0;
}

// Filter cities based on webhook regions if provided
let availableCities = ALL_CITIES;
if (requestedRegions.length > 0) {
  // Map common region names to state abbreviations
  const stateMap = {
    'texas': 'TX', 'florida': 'FL', 'california': 'CA', 'new york': 'NY',
    'illinois': 'IL', 'pennsylvania': 'PA', 'ohio': 'OH', 'georgia': 'GA',
    'north carolina': 'NC', 'michigan': 'MI', 'arizona': 'AZ',
    'washington': 'WA', 'colorado': 'CO', 'tennessee': 'TN',
    'massachusetts': 'MA', 'maryland': 'MD', 'indiana': 'IN',
    'missouri': 'MO', 'wisconsin': 'WI', 'minnesota': 'MN',
    'oregon': 'OR', 'nevada': 'NV', 'oklahoma': 'OK', 'virginia': 'VA',
    'louisiana': 'LA', 'kentucky': 'KY', 'alabama': 'AL',
    'south carolina': 'SC', 'utah': 'UT', 'new mexico': 'NM',
    'nebraska': 'NE', 'iowa': 'IA', 'kansas': 'KS', 'arkansas': 'AR',
    'mississippi': 'MS', 'hawaii': 'HI', 'connecticut': 'CT',
    'new jersey': 'NJ'
  };
  const stateAbbrs = requestedRegions.map(r => stateMap[r] || r.toUpperCase());
  availableCities = ALL_CITIES.filter(c => stateAbbrs.includes(c.state));
}

// Build all city+query combos that haven't been scraped
const pendingJobs = [];
for (const city of availableCities) {
  for (const query of requestedQueries) {
    const key = `${city.name}_${city.state}_${query}`;
    if (!staticData.scrapedCities[key]) {
      pendingJobs.push({
        city: city.name,
        state: city.state,
        lat: city.lat,
        lon: city.lon,
        query: query,
        key: key
      });
    }
  }
}

// Pick next batch
const batch = pendingJobs.slice(0, CITIES_PER_BATCH);

if (batch.length === 0) {
  return [{ json: { _empty: true, reason: 'All cities have been scraped. Reset staticData to re-scrape.', totalCities: availableCities.length, totalScraped: Object.keys(staticData.scrapedCities).length } }];
}

// Increment batch counter
const batchId = new Date().toISOString().split('T')[0] + '_batch_' + staticData.batchIndex;
staticData.batchIndex++;

return batch.map(job => ({
  json: {
    ...job,
    batchId,
    totalPending: pendingJobs.length,
    totalCities: availableCities.length
  }
}));

const response = $input.first().json;
const cityData = $('Has Cities to Scrape?').first().json;

// Mark this city+query as scraped in static data
const staticData = $getWorkflowStaticData('global');
if (staticData.scrapedCities && cityData.key) {
  staticData.scrapedCities[cityData.key] = new Date().toISOString();
}

const results = response.local_results || response.place_results || [];

if (!results || results.length === 0) {
  return [{ json: { _empty: true, reason: 'No results for ' + cityData.city + ', ' + cityData.state + ' (' + cityData.query + ')', city: cityData.city, state: cityData.state, query: cityData.query, batchId: cityData.batchId } }];
}

const leads = results.map(r => {
  const name = r.title || r.name || '';
  const address = r.address || '';
  const phone = r.phone || '';
  const website = r.website || '';
  const rating = r.rating || null;
  const reviews = r.reviews || 0;

  let domain = '';
  if (website) {
    try {
      domain = new URL(website.startsWith('http') ? website : 'https://' + website).hostname.replace('www.', '');
    } catch (e) {
      domain = website.replace(/^https?:\/\//, '').replace(/^www\./, '').split('/')[0];
    }
  }

  return {
    json: {
      business_name: name,
      address,
      phone,
      website,
      domain,
      city: cityData.city,
      state: cityData.state,
      query: cityData.query,
      rating,
      reviews,
      source: 'google_maps',
      batchId: cityData.batchId
    }
  };
}).filter(l => l.json.domain);

if (leads.length === 0) {
  return [{ json: { _empty: true, reason: 'No leads with websites for ' + cityData.city, city: cityData.city, state: cityData.state, query: cityData.query, batchId: cityData.batchId } }];
}

return leads;

// Deduplicate by domain within this batch
const allItems = $input.all();
const seen = new Set();
const unique = [];

for (const item of allItems) {
  const domain = item.json.domain;
  if (domain && !seen.has(domain)) {
    seen.add(domain);
    unique.push(item);
  }
}

return unique;

const dupeCheck = $input.first().json;
const leadData = $('Deduplicate Within Batch').first().json;

// If Supabase returned an array with results, it's a duplicate
const results = Array.isArray(dupeCheck) ? dupeCheck : [];

if (results.length > 0) {
  return [{ json: { _skip: true, reason: 'Duplicate - already in Supabase', domain: leadData.domain, business_name: leadData.business_name } }];
}

return [{ json: { ...leadData, _skip: false } }];

const hunterResponse = $input.first().json;
const leadData = $('Not Duplicate?').first().json;

const data = hunterResponse.data || {};
const emails = data.emails || [];

let bestEmail = '';
let firstName = '';
let lastName = '';

if (emails.length > 0) {
  const sorted = emails.sort((a, b) => (b.confidence || 0) - (a.confidence || 0));
  const best = sorted[0];
  bestEmail = best.value || '';
  firstName = best.first_name || '';
  lastName = best.last_name || '';
}

if (!bestEmail) {
  return [{ json: { _skip: true, reason: 'No email found', business_name: leadData.business_name, domain: leadData.domain } }];
}

return [{
  json: {
    business_name: leadData.business_name,
    email: bestEmail,
    first_name: firstName,
    last_name: lastName,
    phone: leadData.phone,
    website: leadData.website,
    domain: leadData.domain,
    city: leadData.city,
    state: leadData.state,
    rating: leadData.rating,
    reviews: leadData.reviews,
    source: leadData.source,
    batchId: leadData.batchId
  }
}];

const verifyResponse = $input.first().json;
const leadData = $('Has Email?').first().json;

const result = (verifyResponse.result || '').toLowerCase();

const acceptable = ['ok', 'catch_all'];

if (!acceptable.includes(result)) {
  return [{
    json: {
      _skip: true,
      reason: 'Email validation failed: ' + result,
      email: leadData.email,
      business_name: leadData.business_name
    }
  }];
}

return [{
  json: {
    ...leadData,
    email_verified: true,
    email_verify_result: result
  }
}];

// Aggregate results from the entire batch run for reporting
const allSaved = $input.all();
const now = new Date();
const dateStr = now.toISOString().split('T')[0];

// Count successes and failures
let savedCount = 0;
let failedCount = 0;
const citiesSeen = new Set();
const statesSeen = new Set();
const savedLeads = [];

for (const item of allSaved) {
  const d = item.json;
  if (d.id || (Array.isArray(d) && d.length > 0)) {
    savedCount++;
    const lead = Array.isArray(d) ? d[0] : d;
    if (lead.city) citiesSeen.add(lead.city + ', ' + lead.state);
    if (lead.state) statesSeen.add(lead.state);
    savedLeads.push({
      business: lead.business_name || 'Unknown',
      email: lead.email || 'N/A',
      city: lead.city || 'N/A',
      state: lead.state || 'N/A'
    });
  } else {
    failedCount++;
  }
}

const staticData = $getWorkflowStaticData('global');
const totalScraped = Object.keys(staticData.scrapedCities || {}).length;

// Build markdown report
let report = `# Mass Lead Gen Report - ${dateStr}\n\n`;
report += `## Summary\n`;
report += `- **Date**: ${now.toISOString()}\n`;
report += `- **New validated leads saved**: ${savedCount}\n`;
report += `- **Failed/skipped**: ${failedCount}\n`;
report += `- **Cities in batch**: ${citiesSeen.size}\n`;
report += `- **States covered**: ${Array.from(statesSeen).join(', ')}\n`;
report += `- **Total city+query combos scraped to date**: ${totalScraped}\n\n`;

if (savedLeads.length > 0) {
  report += `## New Leads\n\n`;
  report += `| Business | Email | City | State |\n`;
  report += `|----------|-------|------|-------|\n`;
  for (const lead of savedLeads) {
    report += `| ${lead.business} | ${lead.email} | ${lead.city} | ${lead.state} |\n`;
  }
}

return [{
  json: {
    report,
    dateStr,
    savedCount,
    failedCount,
    totalScraped,
    citiesInBatch: citiesSeen.size,
    telegramMessage: `Mass Lead Gen: Scraped ${citiesSeen.size} cities, found ${savedCount} new validated leads. Total city+query combos scraped: ${totalScraped}. Failed/skipped: ${failedCount}.`
  }
}];

// No cities to scrape - notify completion
const data = $input.first().json;
return [{
  json: {
    telegramMessage: 'Mass Lead Gen: All cities have been scraped! Total scraped: ' + (data.totalScraped || 'unknown') + '. Reset static data to re-scrape.',
    _complete: true
  }
}];
